import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface Meal {
  name: string;
  items: string[];
  calories: number;
  prepTime: string;
}

interface MealPlannerData {
  meals: Meal[];
  totalCalories: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const mealData = response.data as MealPlannerData;
  const metaData = response.meta as MetaData;
  const { meals, totalCalories } = mealData;
  const { primaryColor, accentColor } = metaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              Daily Meal Planner
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Total Calories: {totalCalories}
            </Typography>
          </Box>

          {meals.map((meal, index) => (
            <Box key={index}>
              <Stack direction="row" justifyContent="space-between" alignItems="center">
                <Typography variant="body1" fontWeight={500} sx={{ color: accentColor }}>
                  {meal.name}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {meal.calories} cal
                </Typography>
              </Stack>
              <Stack direction="row" spacing={0.5} sx={{ mt: 0.5, mb: 1 }}>
                {meal.items.map((item, idx) => (
                  <Chip key={idx} label={item} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
                ))}
              </Stack>
              <Typography variant="caption" color="text.secondary">
                Prep Time: {meal.prepTime}
              </Typography>
              {index < meals.length - 1 && <Divider sx={{ my: 1 }} />}
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
